changeSet.sql:
UPDATE product_images
SET url = CONCAT('https://picsum.photos/seed/migrated-product-', id, '/900/900')
WHERE url LIKE 'https://source.unsplash.com/%';

UPDATE banners
SET image_url = CONCAT('https://picsum.photos/seed/migrated-banner-', id, '/1400/600')
WHERE image_url LIKE 'https://source.unsplash.com/%';

rollback.sql:
UPDATE product_images
SET url = CONCAT('https://source.unsplash.com/random/900x900?sig=', id)
WHERE url LIKE 'https://picsum.photos/seed/migrated-product-%/900/900';

UPDATE banners
SET image_url = CONCAT('https://source.unsplash.com/random/1400x600?sig=', id)
WHERE image_url LIKE 'https://picsum.photos/seed/migrated-banner-%/1400/600';
